public void testNestedCollectionType() throws Exception
{
    JavaType elem = SimpleType.construct(Point.class);
    JavaType innerCollection = CollectionType.construct(List.class, elem);
    JavaType outerCollection = CollectionType.construct(List.class, innerCollection);

    final String json = aposToQuotes("[ [ {'x':1,'y':2} ], [ {'x':3,'y':4}, {'x':5,'y':6} ] ]");

    List<List<Point>> result = MAPPER.readValue(json, outerCollection);
    assertNotNull(result);
    assertEquals(2, result.size());
    assertEquals(1, result.get(0).size());
    assertEquals(2, result.get(1).size());
    Point p = result.get(1).get(1);
    assertEquals(5, p.x);
    assertEquals(6, p.getY());
}

public void testMapWithComplexValue() throws Exception
{
    JavaType key = SimpleType.construct(String.class);
    JavaType innerKey = SimpleType.construct(String.class);
    JavaType innerValue = SimpleType.construct(Integer.class);
    JavaType innerMap = MapType.construct(Map.class, innerKey, innerValue);
    JavaType outerMap = MapType.construct(Map.class, key, innerMap);

    final String json = aposToQuotes("{'outer':{'a':1,'b':2}}");

    Map<String, Map<String, Integer>> result = MAPPER.readValue(json, outerMap);
    assertNotNull(result);
    assertEquals(1, result.size());
    Map<String, Integer> inner = result.get("outer");
    assertNotNull(inner);
    assertEquals(2, inner.size());
    assertEquals(Integer.valueOf(1), inner.get("a"));
    assertEquals(Integer.valueOf(2), inner.get("b"));
}

public void testEmptyCollectionType() throws Exception
{
    JavaType elem = SimpleType.construct(Point.class);
    JavaType t = CollectionType.construct(List.class, elem);

    final String json = "[]";

    List<Point> l = MAPPER.readValue(json, t);
    assertNotNull(l);
    assertEquals(0, l.size());
}
